/* TODO: letakkan file aset SweetAlert2 asli di public/sweetalert/sweetalert2.all.min.js */
window.Swal = window.Swal || {
    fire: function (options) {
        var hasCancel = options && options.showCancelButton;
        if (hasCancel) {
            var text = (options.title || 'Konfirmasi') + '\n' + ((options.text || options.html || '').replace(/<[^>]*>/g, ''));
            return Promise.resolve({ isConfirmed: window.confirm(text) });
        }

        var message = [options && options.title, options && (options.text || options.html)]
            .filter(Boolean)
            .join('\n');
        if (message) {
            window.alert(message.replace(/<[^>]*>/g, ''));
        }

        return Promise.resolve({ isConfirmed: true });
    }
};